### RxJS Observable Query in React Component

Source: https://github.com/pubkey/rxdb/blob/master/docs/articles/react-indexeddb.html

Illustrates how to create a reactive React component that subscribes to live data updates from an RxDB collection using RxJS Observables and React Hooks. The UI automatically re-renders when the data changes, ensuring real-time synchronization across tabs.

```javascript
import { useState, useEffect } from 'react';

function HeroList({ collection }) {
  const [heroes, setHeroes] = useState([]);

  useEffect(() => {
    // create an observable query
    const query = collection.find();
    const subscription = query.$.subscribe(newHeroes => {
      setHeroes(newHeroes);
    });

    return () => subscription.unsubscribe();
  }, [collection]);

  return (
    <div>
      <h2>Hero List</h2>
      <ul>
        {heroes.map(hero => (
          <li key={hero.id}>
            <strong>{hero.name}</strong> - {hero.power}
          </li>
        ))}
      </ul>
    </div>
  );
}
```

