### React Component with RxDB Reactive Queries (TypeScript/JSX)

Source: https://github.com/pubkey/rxdb/blob/master/docs-src/docs/articles/reactjs-storage.md

Shows a React component that subscribes to RxDB query results using RxJS Observables. The UI automatically updates when the data changes, making it suitable for dynamic offline-first applications.

```tsx
import React, { useEffect, useState } from 'react';

function HeroList({ collection }) {
  const [heroes, setHeroes] = useState([]);

  useEffect(() => {
    const query = collection.find();
    // query.$ is an RxJS Observable that emits whenever data changes
    const sub = query.$.subscribe(newHeroes => {
      setHeroes(newHeroes);
    });

    return () => sub.unsubscribe(); // clean up subscription
  }, [collection]);

  return (
    <ul>
      {heroes.map(hero => (
        <li key={hero.hero.id}>
          {hero.name} - Power: {hero.power}
        </li>
      ))}
    </ul>
  );
}

export default HeroList;
```

